// ═══════════════════════════════════════════════════════════════
// Parse Yescapa & Wikicampers reservation confirmation emails
// ═══════════════════════════════════════════════════════════════

const FRENCH_MONTHS = {
  janvier: '01', 'février': '02', mars: '03', avril: '04',
  mai: '05', juin: '06', juillet: '07', 'août': '08',
  septembre: '09', octobre: '10', novembre: '11', 'décembre': '12'
};

function strip(html) {
  return html
    .replace(/<br\s*\/?>/gi, ' ')
    .replace(/<\/?(p|div|td|th|tr|li|ul|ol|h[1-6])[^>]*>/gi, ' ')
    .replace(/<[^>]+>/g, '')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&#8364;/g, '€')
    .replace(/&euro;/g, '€')
    .replace(/\s+/g, ' ')
    .trim();
}

function parseFrenchDate(t) {
  const m = t.match(/(\d{1,2})\s+([\wéûà]+)\s+(\d{4})/i);
  if (!m) return null;
  const mo = FRENCH_MONTHS[m[2].toLowerCase()];
  return mo ? `${m[3]}-${mo}-${m[1].padStart(2, '0')}` : null;
}

function parseDdMm(t) {
  const m = t.match(/(\d{2})\/(\d{2})\/(\d{4})/);
  return m ? `${m[3]}-${m[2]}-${m[1]}` : null;
}

function addOneDay(dateStr) {
  const d = new Date(dateStr + 'T00:00:00');
  d.setDate(d.getDate() + 1);
  return d.toISOString().slice(0, 10);
}

const results = [];

for (const item of $input.all()) {
  const from = (item.json.from || '').toLowerCase();
  const subject = (item.json.subject || '').toLowerCase();
  const html = item.json.html || item.json.textHtml || '';

  let parsed = null;

  // ── Yescapa ──────────────────────────────────────────────
  if (from.includes('yescapa.com') && subject.includes('réservation')) {
    const ref = html.match(/réservation\s*(?::\s*)?#(\d{5,})/i) || html.match(/#(\d{5,})/);
    if (!ref) continue;

    const getVal = (label) => {
      const rx = new RegExp(`<th[^>]*>[^<]*${label}[^<]*</th>\\s*<td[^>]*>([\\s\\S]*?)</td>`, 'i');
      return (html.match(rx) || [])[1] || '';
    };
    const strong = (s) => (s.match(/<strong[^>]*>([\s\S]*?)<\/strong>/i) || [])[1] || '';

    const startDate = parseFrenchDate(strip(strong(getVal('Départ'))));
    const endDate = parseFrenchDate(strip(strong(getVal('Retour'))));
    if (!startDate || !endDate) continue;

    const vanLink = getVal('Véhicule').match(/<a[^>]*>([^<]+)<\/a>/i);
    const vanName = vanLink ? vanLink[1].trim() : strip(strong(getVal('Véhicule'))) || 'Van';
    const revText = strip(strong(getVal('Rémunération')));
    const revMatch = revText.match(/([\d\s,]+)\s*€/);
    const revenue = revMatch ? parseFloat(revMatch[1].replace(/\s/g, '').replace(',', '.')) : null;
    const insurance = strip(strong(getVal('Assurance'))) || null;

    parsed = {
      platform: 'yescapa',
      platformLabel: 'Yescapa',
      ref: ref[1],
      vanName,
      startDate,
      endDate,
      endDateExclusive: addOneDay(endDate),
      revenue,
      insurance,
      colorId: '3'
    };
  }

  // ── Wikicampers ──────────────────────────────────────────
  else if (from.includes('wikicampers.fr') && subject.includes('confirmée')) {
    const text = strip(html);
    const ref = text.match(/N°\s*de\s*réservation\s*(\d+)/i);
    if (!ref) continue;

    const veh = text.match(/Véhicule\s+(.+?)\s+Départ/i);
    const dep = text.match(/Départ\s+(\d{2}\/\d{2}\/\d{4})/i);
    const ret = text.match(/Retour\s+(\d{2}\/\d{2}\/\d{4})/i);
    const gain = text.match(/Votre gain\s+([\d\s,]+)\s*€/i);

    const startDate = dep ? parseDdMm(dep[1]) : null;
    const endDate = ret ? parseDdMm(ret[1]) : null;
    if (!startDate || !endDate) continue;

    parsed = {
      platform: 'wikicampers',
      platformLabel: 'Wikicampers',
      ref: ref[1],
      vanName: veh ? veh[1].trim() : 'Van',
      startDate,
      endDate,
      endDateExclusive: addOneDay(endDate),
      revenue: gain ? parseFloat(gain[1].replace(/\s/g, '').replace(',', '.')) : null,
      insurance: null,
      colorId: '6'
    };
  }

  if (!parsed) continue;

  // Prepare outputs for Calendar + Telegram
  const revenueStr = parsed.revenue ? `${parsed.revenue.toFixed(2).replace('.', ',')}€` : 'N/A';

  results.push({
    json: {
      ...parsed,
      calendarTitle: `\uD83D\uDE90 ${parsed.vanName} — ${parsed.platformLabel} #${parsed.ref}`,
      calendarDescription: [
        `Plateforme: ${parsed.platformLabel}`,
        `Ref: #${parsed.ref}`,
        parsed.revenue ? `Revenu: ${revenueStr}` : null,
        parsed.insurance ? `Assurance: ${parsed.insurance}` : null
      ].filter(Boolean).join('\n'),
      telegramMessage: `\uD83D\uDCC5 Nouvelle réservation ${parsed.platformLabel}!\n\uD83D\uDE90 ${parsed.vanName}\n\uD83D\uDCC6 ${parsed.startDate} → ${parsed.endDate}\n\uD83D\uDCB0 ${revenueStr}\n\uD83D\uDD16 Ref #${parsed.ref}`
    }
  });
}

return results;
